import{_ as a,c as l,o as r,ae as t}from"./chunks/framework.CDjunVez.js";const c=JSON.parse('{"title":"數位主權之爭：全球網路治理與跨境平台監管浪潮","description":"從數據落地到產業保護，各國政府正透過立法重新定義網路疆界。中國要求數據在地化、印尼封殺 TikTok Shop、越南逼退 Shein 與 Temu，這不僅是監管政策的轉變，更是一場關於數位主權、經濟保護主義與全球化退潮的角力戰。","frontmatter":{"title":"數位主權之爭：全球網路治理與跨境平台監管浪潮","description":"從數據落地到產業保護，各國政府正透過立法重新定義網路疆界。中國要求數據在地化、印尼封殺 TikTok Shop、越南逼退 Shein 與 Temu，這不僅是監管政策的轉變，更是一場關於數位主權、經濟保護主義與全球化退潮的角力戰。","date":"2025-12-10T00:00:00.000Z","author":"Clement Tang","tags":["網路治理","數據落地","跨境電商","數位主權","個資保護","產業保護"],"category":"articles","status":"published","lastModified":"2026-01-27T00:00:00.000Z"},"headers":[],"relativePath":"articles/2025-12-10-internet-governance-regulation.md","filePath":"articles/2025-12-10-internet-governance-regulation.md"}'),e={name:"articles/2025-12-10-internet-governance-regulation.md"};function o(n,i,s,g,h,u){return r(),l("div",null,[...i[0]||(i[0]=[t('<h1 id="數位主權之爭-全球網路治理與跨境平台監管浪潮" tabindex="-1">數位主權之爭：全球網路治理與跨境平台監管浪潮 <a class="header-anchor" href="#數位主權之爭-全球網路治理與跨境平台監管浪潮" aria-label="Permalink to &quot;數位主權之爭：全球網路治理與跨境平台監管浪潮&quot;">​</a></h1><blockquote><p>從數據落地到產業保護，各國政府正透過立法重新定義網路疆界。中國要求數據在地化、印尼封殺 TikTok Shop、越南逼退 Shein 與 Temu，這不僅是監管政策的轉變，更是一場關於數位主權、經濟保護主義與全球化退潮的角力戰。</p></blockquote><hr><h2 id="引言-數位疆界的重劃" tabindex="-1">引言：數位疆界的重劃 <a class="header-anchor" href="#引言-數位疆界的重劃" aria-label="Permalink to &quot;引言：數位疆界的重劃&quot;">​</a></h2><p>過去十年，網路被視為無國界的全球公域。然而，這個共識正在瓦解。從 2015 年俄羅斯的數據落地法到 2025 年美國的 TikTok 禁令，各國政府正透過立法手段，對境外網路平台與服務施加前所未有的控制。</p><p><strong>本文將深入探討：</strong></p><ul><li>數據落地（Data Localization）的全球趨勢與政策演變</li><li>資料治理與個人資料保護的法規框架（GDPR、PIPL 等）</li><li>跨境電商監管與本地產業保護動機</li><li>過去十年全球重要監管事件的案例分析</li><li>數位主權與經濟保護主義的交織關係</li></ul><p><strong>核心問題：</strong> 這些監管措施究竟是為了保護國家安全與公民隱私，還是披著合法外衣的數位保護主義？</p><hr><h2 id="一、數據落地-全球趨勢與政策演變" tabindex="-1">一、數據落地：全球趨勢與政策演變 <a class="header-anchor" href="#一、數據落地-全球趨勢與政策演變" aria-label="Permalink to &quot;一、數據落地：全球趨勢與政策演變&quot;">​</a></h2><h3 id="_1-1-什麼是數據落地" tabindex="-1">1.1 什麼是數據落地？ <a class="header-anchor" href="#_1-1-什麼是數據落地" aria-label="Permalink to &quot;1.1 什麼是數據落地？&quot;">​</a></h3><p>數據落地（Data Localization）是指要求在一國境內收集的數據必須儲存、處理或保留在該國境內的政策。截至 2025 年，<strong>全球約 75% 的國家已實施某種形式的數據落地規定</strong>。</p><h3 id="_1-2-全球數據落地的三波浪潮" tabindex="-1">1.2 全球數據落地的三波浪潮 <a class="header-anchor" href="#_1-2-全球數據落地的三波浪潮" aria-label="Permalink to &quot;1.2 全球數據落地的三波浪潮&quot;">​</a></h3><p><strong>第一波（2015-2017）：先行者的探索</strong></p><ul><li><strong>俄羅斯</strong>（2015）：率先要求所有處理俄羅斯公民個人資料的公司必須在俄羅斯境內儲存數據</li><li><strong>中國</strong>（2017）：《網路安全法》生效，要求關鍵信息基礎設施運營者在中國境內儲存個人信息和重要數據</li></ul><p><strong>第二波（2018-2021）：區域擴散</strong></p><ul><li><strong>印度</strong>（2018-2021）：金融、電信等特定行業開始實施數據在地化要求</li><li><strong>越南</strong>（2019）：《網路安全法》要求科技公司在越南設立辦公室並儲存用戶數據</li><li><strong>印尼</strong>（2020-2022）：分階段推動電子系統運營商（ESO）數據在地化</li></ul><p><strong>第三波（2022-2025）：全面強化</strong></p><ul><li><strong>中國</strong>（2024-2025）：《網路數據安全管理條例》於 2025 年 1 月生效，進一步細化數據出境管理</li><li><strong>印度</strong>（2025）：DPDPA 實施規則發布，對重要數據受託人引入數據落地義務</li><li><strong>巴西</strong>（2024）：ANPD 發布跨境數據傳輸新規，要求使用標準合約條款</li></ul><h3 id="_1-3-2025-年的執法趨勢" tabindex="-1">1.3 2025 年的執法趨勢 <a class="header-anchor" href="#_1-3-2025-年的執法趨勢" aria-label="Permalink to &quot;1.3 2025 年的執法趨勢&quot;">​</a></h3><p><strong>罰款金額激增：</strong></p><ul><li><strong>歐盟 GDPR</strong>：違規罰款最高可達 2,000 萬歐元或全球年營收的 4%</li><li><strong>2025 年 5 月</strong>：愛爾蘭 DPC 對 TikTok 處以 5.3 億歐元罰款，原因是非法將歐盟用戶數據傳輸至中國</li><li><strong>2023 年 5 月</strong>：Meta 因將 Facebook 用戶數據從歐盟傳輸到美國而被罰款 12 億歐元</li></ul><p><strong>跨境數據傳輸框架的挑戰：</strong></p><ul><li>EU-U.S. Data Privacy Framework（DPF）在 2025 年面臨法律挑戰，可能危及歐美之間的數據傳輸</li><li>監管機構越來越要求進行傳輸影響評估（Transfer Impact Assessments, TIAs）</li><li>Standard Contractual Clauses（SCCs）的審查趨嚴</li></ul><hr><h2 id="二、資料治理與個人資料保護-全球法規框架" tabindex="-1">二、資料治理與個人資料保護：全球法規框架 <a class="header-anchor" href="#二、資料治理與個人資料保護-全球法規框架" aria-label="Permalink to &quot;二、資料治理與個人資料保護：全球法規框架&quot;">​</a></h2><h3 id="_2-1-歐盟-gdpr-全球標準的制定者" tabindex="-1">2.1 歐盟 GDPR：全球標準的制定者 <a class="header-anchor" href="#_2-1-歐盟-gdpr-全球標準的制定者" aria-label="Permalink to &quot;2.1 歐盟 GDPR：全球標準的制定者&quot;">​</a></h3><p><strong>基本框架：</strong></p><ul><li>2018 年 5 月生效，成為全球最嚴格的個資保護法規</li><li>適用於所有處理歐盟居民個人資料的組織，具域外效力</li><li>罰款：最高 2,000 萬歐元或全球年營收 4%</li></ul><p><strong>2025 年執法強化：</strong></p><ul><li>資料洩露通報時限從 72 小時縮短至 48 小時（醫療、能源、電信業）</li><li>歐盟撥款 2,000 萬歐元資助 2025 年審計</li><li>DPAs 對跨境數據傳輸的審查更加嚴格</li></ul><p><strong>重大罰款案例：</strong></p><ul><li>Meta（2023）：12 億歐元（跨境數據傳輸）</li><li>TikTok（2025）：5.3 億歐元（跨境數據傳輸）</li><li>Uber（2024）：2.9 億歐元（敏感數據傳輸）</li></ul><h3 id="_2-2-中國-數據三法體系" tabindex="-1">2.2 中國：數據三法體系 <a class="header-anchor" href="#_2-2-中國-數據三法體系" aria-label="Permalink to &quot;2.2 中國：數據三法體系&quot;">​</a></h3><p>中國建立了以《網路安全法》（2017）、《數據安全法》（2021）、《個人信息保護法》（PIPL, 2021）為核心的「數據三法」體系。</p><p><strong>《網路數據安全管理條例》（2025 年 1 月生效）：</strong></p><ul><li>作為三法的配套行政法規，細化網路安全和數據保護框架</li><li>明確「重要數據」定義：特定領域、群體、地區或達到一定精度和規模的數據，若被篡改、破壞、洩露或非法獲取使用，可能直接危害國家安全、經濟運行、社會穩定或公共健康安全</li><li>豁免清單：跨境購物、跨境配送、跨境匯款、跨境支付、航班與酒店預訂、跨境人力資源管理、離岸數據處理等場景豁免數據出境安全評估</li></ul><p><strong>《促進和規範數據跨境流動規定》（2024 年 3 月）：</strong></p><ul><li>實施一年後，每月數據出境安全評估申請下降約 60%</li><li>每月個人信息出境標準合約備案下降約 50%</li><li>中國與香港、澳門、德國、歐盟開展跨境數據流動國際合作</li></ul><p><strong>核心原則：</strong></p><ul><li>中國的數據出境管理並非針對所有數據，而是限於重要數據和個人信息</li><li>一般數據若不涉及個人信息或重要數據，可自由跨境流動</li><li>重要數據和達到規定數量的個人信息在通過數據出境安全評估後可合法跨境流動</li></ul><h3 id="_2-3-其他重要法規" tabindex="-1">2.3 其他重要法規 <a class="header-anchor" href="#_2-3-其他重要法規" aria-label="Permalink to &quot;2.3 其他重要法規&quot;">​</a></h3><p><strong>印度 DPDPA（Digital Personal Data Protection Act）：</strong></p><ul><li>2023 年 8 月通過，2025 年 1 月發布實施細則，2025 年 11 月 14 日正式生效</li><li>第 16 條允許個人資料自由傳輸至所有國家或地區，除非中央政府特別列入黑名單</li><li><strong>爭議性條款</strong>：對重要數據受託人（Significant Data Fiduciaries, SDFs）可能施加數據在地化義務，但這與 DPDPA 的跨境傳輸架構存在矛盾</li><li>實施分階段：DPB 條款立即生效，同意管理框架 12 個月後生效，更廣泛的合規義務 18 個月後生效</li></ul><p><strong>巴西 LGPD：</strong></p><ul><li>2024 年 8 月，ANPD 發布第 19/2024 號決議，規範跨境個人資料傳輸</li><li>要求使用 ANPD 批准的標準合約條款（SCCs）</li><li>企業有 12 個月（至 2025 年 8 月 22 日）將 ANPD 批准的標準條款納入合約</li><li>巴西尚未認定任何國家（包括美國）為提供「充分保護」的國家</li></ul><p><strong>澳洲隱私法改革（2024 年 12 月）：</strong></p><ul><li>Privacy and Other Legislation Amendment Act 2024 於 2024 年 12 月 10 日獲得御准，12 月 11 日部分生效</li><li>引入「白名單」機制：允許向提供實質類似 APPs 保護的國家或約束性計畫自由傳輸個人資料</li><li>預期白名單將包括 GDPR 治理的歐盟和英國等成熟數據保護法國家</li><li><strong>目前尚無白名單</strong>，企業仍需採取合理步驟確保海外接收者不違反 APPs</li></ul><p><strong>南韓 PIPA（Personal Information Protection Act）：</strong></p><ul><li>2024 年 4 月，PIPC 發布《個人信息保護法適用於境外業務經營者指南》</li><li>重點監管跨境數據傳輸，而非嚴格的數據在地化</li><li>2025 年 1 月，PIPC 對 KakaoPay 處以 59 億韓元、對 Apple Distribution International Limited 處以 24 億韓元行政處罰，原因是未通知用戶其與 Alipay 的服務關係涉及跨境處理個人信息</li><li>2025 年 10 月 2 日起，境外實體指定國內代表的義務進一步加強</li></ul><hr><h2 id="三、跨境電商監管-產業保護的新戰場" tabindex="-1">三、跨境電商監管：產業保護的新戰場 <a class="header-anchor" href="#三、跨境電商監管-產業保護的新戰場" aria-label="Permalink to &quot;三、跨境電商監管：產業保護的新戰場&quot;">​</a></h2><h3 id="_3-1-印尼封殺-tiktok-shop-2023" tabindex="-1">3.1 印尼封殺 TikTok Shop（2023） <a class="header-anchor" href="#_3-1-印尼封殺-tiktok-shop-2023" aria-label="Permalink to &quot;3.1 印尼封殺 TikTok Shop（2023）&quot;">​</a></h3><p><strong>時間線：</strong></p><ul><li><strong>2023 年 9 月 28 日</strong>：印尼發布更嚴格的電商交易法規，禁止社交媒體平台上的電商交易</li><li><strong>2023 年 10 月 4 日</strong>：TikTok 印尼表示將在貿易部設定的一週期限內停止電商市集交易，否則將面臨關閉風險</li></ul><p><strong>政府理由：</strong></p><ul><li><strong>保護國內電商平台</strong>：防範掠奪性定價對傳統小型企業的不公平競爭</li><li><strong>保護微中小型企業（MSMEs）</strong>：TikTok Shop 的低價策略被視為對線下傳統商家的威脅</li><li><strong>保護消費者個人資料</strong></li><li><strong>禁止海外賣家</strong> 在國內電商平台上運營</li></ul><p><strong>影響：</strong></p><ul><li>TikTok 印尼稱此決定將影響 600 萬賣家和近 700 萬聯盟創作者的生計</li><li>印尼是 TikTok 最大的東南亞市場，全球第二大市場（1.25 億用戶，僅次於美國）</li></ul><p><strong>後續發展（2024）：</strong></p><ul><li>TikTok 向 GoTo 旗下電商部門 Tokopedia 投資 15 億美元後，有望在印尼重啟線上購物業務</li></ul><h3 id="_3-2-越南迫使-shein-與-temu-撤出-2024" tabindex="-1">3.2 越南迫使 Shein 與 Temu 撤出（2024） <a class="header-anchor" href="#_3-2-越南迫使-shein-與-temu-撤出-2024" aria-label="Permalink to &quot;3.2 越南迫使 Shein 與 Temu 撤出（2024）&quot;">​</a></h3><p><strong>時間線：</strong></p><ul><li><strong>2024 年 11 月初</strong>：越南政府要求 Shein 和 Temu 在 11 月底前完成本地註冊</li><li><strong>2024 年 12 月</strong>：越南工貿部要求 Temu 和 Shein 暫停跨境電商業務，原因是未能滿足商業註冊截止日期</li><li>Temu 在進入市場僅兩個月後被要求暫停業務</li></ul><p><strong>監管要求：</strong></p><ul><li><strong>商業註冊</strong>：越南要求外國電商平台在當地完成商業註冊</li><li><strong>新稅法（2024 年 11 月）</strong>：越南國會批准稅法修正案，要求外國電商平台的本地運營商繳納增值稅（VAT），取消自 2010 年以來對價值低於 100 萬越南盾進口商品的 VAT 豁免和免稅優惠</li></ul><p><strong>政府關切：</strong></p><ul><li><strong>定價策略</strong>：越南監管機構和本地企業對中國電商平台的定價策略表示擔憂</li><li><strong>仿冒品風險</strong>：貿易部發現與仿冒品分銷相關的潛在風險</li></ul><p><strong>當前狀態：</strong></p><ul><li>Temu 和 Shein 確認正與越南貿易部合作，完成必要程序</li></ul><h3 id="_3-3-台灣-打詐四法與跨境電商監管-2024" tabindex="-1">3.3 台灣：打詐四法與跨境電商監管（2024） <a class="header-anchor" href="#_3-3-台灣-打詐四法與跨境電商監管-2024" aria-label="Permalink to &quot;3.3 台灣：打詐四法與跨境電商監管（2024）&quot;">​</a></h3><p><strong>打詐四法（2024 年 7 月通過）：</strong></p><p>立法院於 2024 年 7 月 12 日通過《打詐專法》（詐欺犯罪危害防制條例）和《通訊保障及監察法》修正案，7 月 16 日完成其餘兩法，建立台灣反詐欺法律框架的新里程碑。</p><p><strong>境外網路廣告平台監管：</strong></p><ul><li><strong>設立法定代表人</strong>：一定規模的境外網路廣告平台必須在台灣設立法定代表人，並配合政府進行詐欺防制</li><li><strong>罰款</strong>：未設立代表人或未移除詐欺廣告者，可處 250 萬至 2,500 萬新台幣罰款</li><li><strong>服務封鎖</strong>：嚴重違規者可能面臨服務封鎖</li><li><strong>適用平台</strong>：預期包括 TikTok、Facebook、Google 等</li></ul><p><strong>平台責任：</strong></p><ul><li>平台運營商必須主動或經通知後，在指定時間內移除、限制瀏覽或停止播送廣告</li><li>必須向執法機構提供廣告委託人和資助者的資訊</li><li>違規者可能與廣告主承擔連帶賠償責任</li></ul><p><strong>虛擬貨幣與洗錢防制：</strong></p><ul><li>虛擬資產服務提供商和第三方支付服務必須完成反洗錢和服務能力註冊</li><li>違規者可處最高 2 年有期徒刑或最高 500 萬新台幣罰款</li></ul><p><strong>民間團體關切：</strong></p><ul><li>憂慮「打詐四法」可能緊急封網、監控上網資料、凍結可疑帳戶，恐侵害人權</li><li>呼籲立法院嚴格審查</li></ul><h3 id="_3-4-泰國-外國電商平台稅收與資訊揭露-2024" tabindex="-1">3.4 泰國：外國電商平台稅收與資訊揭露（2024） <a class="header-anchor" href="#_3-4-泰國-外國電商平台稅收與資訊揭露-2024" aria-label="Permalink to &quot;3.4 泰國：外國電商平台稅收與資訊揭露（2024）&quot;">​</a></h3><p><strong>外國電子服務提供商 VAT 註冊：</strong></p><ul><li>年收入超過 180 萬泰銖的外國數位平台服務提供商（包括 Facebook、Netflix、Google、Apple、TikTok、Agoda）必須向泰國稅務局繳納 VAT</li><li>電子服務提供商必須通過線上系統「VAT for Electronic Service (VES)」註冊為 VAT 登記人</li></ul><p><strong>平台收入報告要求（2024 年 1 月生效）：</strong></p><ul><li>泰國稅務局於 2023 年 12 月 27 日發布新規，要求電商平台設立特別帳戶，向稅務局提交電商賣家的收入資訊</li><li>執法從 2024 年 1 月 1 日週期開始</li></ul><p><strong>進口商品 VAT（2024 年 7 月 5 日生效）：</strong></p><ul><li>泰國政府於 2024 年 6 月 20 日宣布，自 2024 年 7 月 5 日起，對每件不超過 1,500 泰銖的進口產品徵收 7% 增值稅</li><li>此前價值 1-1,500 泰銖（CIF - 成本、保險和運費）的進口商品未被徵收 VAT</li></ul><p><strong>一般 VAT 要求：</strong></p><ul><li>年收入超過 180 萬泰銖（約 50,000 美元）的企業，通常 VAT 稅率為 7%</li></ul><h3 id="_3-5-法國-gafa-稅-數位服務稅的先驅-2019-2025" tabindex="-1">3.5 法國 GAFA 稅：數位服務稅的先驅（2019-2025） <a class="header-anchor" href="#_3-5-法國-gafa-稅-數位服務稅的先驅-2019-2025" aria-label="Permalink to &quot;3.5 法國 GAFA 稅：數位服務稅的先驅（2019-2025）&quot;">​</a></h3><p><strong>背景與名稱由來：</strong></p><ul><li>2019 年 7 月，法國實施數位服務稅（Digital Services Tax, DST），俗稱「GAFA 稅」或「GAFAM 稅」，因其旨在對 Google、Apple、Facebook（現 Meta）、Amazon 和 Microsoft 等科技巨頭徵稅</li></ul><p><strong>現行稅率（2019-2024）：</strong></p><ul><li>對數位服務提供商的總營收徵收 3% 的固定稅率</li><li>2024 年徵收 7 億歐元稅收</li></ul><p><strong>資格標準：</strong></p><ul><li>全球應稅服務營收超過 7.5 億歐元</li><li>法國境內營收超過 2,500 萬歐元</li><li>適用於特定被視為在該國提供的數位服務</li></ul><p><strong>2025 年提案增稅：</strong></p><ul><li>國民議會已通過修正案，將 DST 稅率從 3% 提高至 5%</li><li>此調整旨在為國家預算額外產生 5 億歐元收入</li><li>最終投票原定於 2024 年 12 月 12 日</li></ul><p><strong>國際背景：</strong></p><ul><li>許多國家仍在等待 OECD 兩支柱計畫的最終決定，擔心美國貿易制裁報復</li><li>法國正考慮修改 DST 規則以減少預算赤字</li></ul><hr><h2 id="四、數位主權與產業保護-動機分析" tabindex="-1">四、數位主權與產業保護：動機分析 <a class="header-anchor" href="#四、數位主權與產業保護-動機分析" aria-label="Permalink to &quot;四、數位主權與產業保護：動機分析&quot;">​</a></h2><h3 id="_4-1-數位主權的多重面向" tabindex="-1">4.1 數位主權的多重面向 <a class="header-anchor" href="#_4-1-數位主權的多重面向" aria-label="Permalink to &quot;4.1 數位主權的多重面向&quot;">​</a></h3><p><strong>定義演變：</strong></p><ul><li><strong>早期定義</strong>：政府控制數位基礎設施和數據流動的能力</li><li><strong>當前理解</strong>：「一個有序、受監管和安全的數位領域」的簡稱</li></ul><p><strong>三大支柱：</strong></p><p><strong>1. 國家安全考量</strong></p><ul><li>防止外國政府透過數據存取進行監控或情報收集</li><li>保護關鍵基礎設施免受外部威脅</li><li>案例：美國對 TikTok 的國家安全擔憂</li></ul><p><strong>2. 隱私保護訴求</strong></p><ul><li>保障公民個人資料不被跨國公司濫用</li><li>建立符合本地價值觀的隱私標準</li><li>案例：GDPR 的誕生</li></ul><p><strong>3. 經濟與產業政策</strong></p><ul><li>「數據即商品」的觀點：需要擁有、控制和保護</li><li>優先本地供應商以刺激創新、創造高技能就業、保留經濟價值</li><li>案例：印尼、越南對外國電商平台的限制</li></ul><h3 id="_4-2-經濟保護主義的證據" tabindex="-1">4.2 經濟保護主義的證據 <a class="header-anchor" href="#_4-2-經濟保護主義的證據" aria-label="Permalink to &quot;4.2 經濟保護主義的證據&quot;">​</a></h3><p><strong>數位主權作為工業政策：</strong> 根據研究，數位主權通常與建構強大的國內科技產業交織在一起，政府優先本地供應商以刺激創新、創造高技能就業，並將經濟價值保留在國內。</p><p><strong>數據在地化作為保護主義工具：</strong></p><ul><li>數據在地化被描述為「一種數位產業政策形式，一種強迫發展國內數據處理和分析產業的方式」</li><li>透過限制外國市場准入、強制數據在地化、優先本地公司等保護主義措施</li></ul><p><strong>經濟影響研究：</strong></p><ul><li>限制性數據在地化政策具有顯著的負面經濟後果</li><li>減少貿易量、提高營運成本、增加進口價格、抑制創新</li><li>鼓勵保護主義，使美國科技公司更難以競爭</li></ul><h3 id="_4-3-案例分析-保護主義-vs-正當監管" tabindex="-1">4.3 案例分析：保護主義 vs. 正當監管 <a class="header-anchor" href="#_4-3-案例分析-保護主義-vs-正當監管" aria-label="Permalink to &quot;4.3 案例分析：保護主義 vs. 正當監管&quot;">​</a></h3><p><strong>明顯的保護主義案例：</strong></p><p><strong>印尼 TikTok Shop 禁令</strong></p><ul><li><strong>官方理由</strong>：保護 MSMEs、防止掠奪性定價</li><li><strong>實際效果</strong>：保護本地電商平台（如 Tokopedia、Shopee）免受外國競爭</li><li><strong>證據</strong>：僅針對社交商務，傳統電商平台未受影響</li></ul><p><strong>越南對 Shein/Temu 的行動</strong></p><ul><li><strong>官方理由</strong>：商業註冊、稅收合規、仿冒品控制</li><li><strong>實際效果</strong>：在中國電商快速增長時保護本地零售業</li><li><strong>證據</strong>：新 VAT 規則恰好在這些平台快速增長時實施</li></ul><p><strong>合理監管案例：</strong></p><p><strong>GDPR 跨境數據傳輸限制</strong></p><ul><li><strong>理由</strong>：保護歐盟公民隱私權</li><li><strong>證據</strong>： <ul><li>對所有非歐盟國家一視同仁（包括美國、中國）</li><li>提供合法傳輸機制（SCCs、BCRs、adequacy decisions）</li><li>基於歐盟基本權利憲章</li></ul></li></ul><p><strong>台灣打詐四法</strong></p><ul><li><strong>理由</strong>：打擊詐欺犯罪、保護消費者</li><li><strong>證據</strong>： <ul><li>適用於所有廣告平台（本地和外國）</li><li>聚焦於詐欺內容，而非商業競爭</li><li>提供合規路徑（設立代表人）</li></ul></li></ul><p><strong>灰色地帶：</strong></p><p><strong>中國數據三法</strong></p><ul><li><strong>官方理由</strong>：國家安全、數據安全、隱私保護</li><li><strong>爭議點</strong>： <ul><li>「重要數據」定義廣泛且模糊</li><li>對外國公司施加不成比例的負擔</li><li>可能用於產業政策目的</li></ul></li><li><strong>平衡觀點</strong>： <ul><li>2024 年《促進和規範數據跨境流動規定》顯示務實化趨勢</li><li>豁免清單涵蓋合法商業場景</li><li>評估申請量大幅下降（60%）</li></ul></li></ul><h3 id="_4-4-全球競爭的三極格局" tabindex="-1">4.4 全球競爭的三極格局 <a class="header-anchor" href="#_4-4-全球競爭的三極格局" aria-label="Permalink to &quot;4.4 全球競爭的三極格局&quot;">​</a></h3><p><strong>美國模式：市場主導</strong></p><ul><li>強調言論自由和創新</li><li>輕度監管，依賴企業自律</li><li>但對中國應用（TikTok）採取嚴厲立場</li></ul><p><strong>中國模式：國家控制</strong></p><ul><li>強調網路主權和安全</li><li>嚴格的內容審查和數據在地化</li><li>培育本地科技巨頭（BAT、字節跳動）</li></ul><p><strong>歐盟模式：權利保護</strong></p><ul><li>強調基本權利和隱私</li><li>透過 GDPR、DMA、DSA 建立全球標準</li><li>對美國和中國科技巨頭皆嚴格監管</li></ul><p>這三種模式的競爭加深了地緣政治競爭，並導致全球網路的「分裂化」（Splinternet）。</p><hr><h2 id="五、歐盟數位市場法-dma-守門人監管" tabindex="-1">五、歐盟數位市場法（DMA）：守門人監管 <a class="header-anchor" href="#五、歐盟數位市場法-dma-守門人監管" aria-label="Permalink to &quot;五、歐盟數位市場法（DMA）：守門人監管&quot;">​</a></h2><h3 id="_5-1-指定守門人與核心平台服務" tabindex="-1">5.1 指定守門人與核心平台服務 <a class="header-anchor" href="#_5-1-指定守門人與核心平台服務" aria-label="Permalink to &quot;5.1 指定守門人與核心平台服務&quot;">​</a></h3><p><strong>守門人認定（截至 2025 年）：</strong></p><ul><li><strong>2023 年 9 月 6 日</strong>：歐盟委員會指定六家守門人：Alphabet、Amazon、Apple、ByteDance、Meta、Microsoft</li><li>22 項服務被確定為「核心平台服務」</li></ul><p><strong>後續指定：</strong></p><ul><li><strong>2024 年 4 月</strong>：經歐盟委員會市場調查，iPadOS 被視為守門人核心平台服務</li><li><strong>2024 年 5 月</strong>：Booking.com 因線上旅遊中介服務成為最新添加者</li></ul><p><strong>各公司指定服務（截至 2025 年）：</strong></p><ul><li><strong>Google（Alphabet）</strong>：8 項服務（搜尋、YouTube、Android、Chrome、Google Maps、Google Play、Google Shopping、Google Ads）</li><li><strong>Meta Platforms</strong>：4 項服務（Facebook、Instagram、WhatsApp、Messenger）</li><li><strong>Apple</strong>：4 項服務（App Store、iOS、Safari、iPadOS）</li><li><strong>ByteDance</strong>：僅 TikTok</li></ul><h3 id="_5-2-合規與執法" tabindex="-1">5.2 合規與執法 <a class="header-anchor" href="#_5-2-合規與執法" aria-label="Permalink to &quot;5.2 合規與執法&quot;">​</a></h3><p><strong>合規期限：</strong></p><ul><li>守門人必須在 2024 年 3 月 6 日前遵守 DMA 所有條款</li><li>從 2024 年 3 月 7 日起，守門人必須符合 DMA 規定</li></ul><p><strong>執法行動：</strong></p><ul><li><strong>2024 年 3 月 25 日</strong>：對 Alphabet、Apple、Meta 展開涉嫌不合規調查</li><li><strong>2024 年 6 月 24 日</strong>：Apple 成為首家根據 DMA 被起訴的公司</li></ul><p><strong>Microsoft 例外：</strong></p><ul><li><strong>2024 年 2 月 13 日</strong>：歐盟委員會宣布 Bing、Edge、Microsoft Advertising 和 iMessage 不符合守門人服務資格</li></ul><h3 id="_5-3-dma-的全球影響" tabindex="-1">5.3 DMA 的全球影響 <a class="header-anchor" href="#_5-3-dma-的全球影響" aria-label="Permalink to &quot;5.3 DMA 的全球影響&quot;">​</a></h3><p>DMA 要求守門人：</p><ul><li>允許第三方應用程式和應用商店</li><li>允許用戶卸載預裝應用</li><li>禁止偏袒自家服務</li><li>與競爭對手共享某些數據</li><li>提高演算法透明度</li></ul><p>這些要求正在改變全球科技公司的商業模式，即使在歐盟以外地區。</p><hr><h2 id="六、美國-tiktok-禁令-國家安全-vs-言論自由-2024-2025" tabindex="-1">六、美國 TikTok 禁令：國家安全 vs. 言論自由（2024-2025） <a class="header-anchor" href="#六、美國-tiktok-禁令-國家安全-vs-言論自由-2024-2025" aria-label="Permalink to &quot;六、美國 TikTok 禁令：國家安全 vs. 言論自由（2024-2025）&quot;">​</a></h2><h3 id="_6-1-立法進程" tabindex="-1">6.1 立法進程 <a class="header-anchor" href="#_6-1-立法進程" aria-label="Permalink to &quot;6.1 立法進程&quot;">​</a></h3><p><strong>《保護美國人免受外國對手控制應用程式法案》（PAFACA）：</strong></p><ul><li><strong>2024 年 3 月 13 日</strong>：美國眾議院以跨黨派支持通過</li><li><strong>2024 年 4 月 24 日</strong>：拜登總統簽署成為法律</li><li><strong>2025 年 1 月 19 日</strong>：禁令生效，原因是美國政府對中華人民共和國政府可能的用戶數據收集和影響力操作的擔憂</li></ul><h3 id="_6-2-國家安全關切" tabindex="-1">6.2 國家安全關切 <a class="header-anchor" href="#_6-2-國家安全關切" aria-label="Permalink to &quot;6.2 國家安全關切&quot;">​</a></h3><p><strong>兩大主要領域：</strong></p><p><strong>1. 數據收集</strong></p><ul><li>TikTok 能夠收集大量個人資訊，包括姓名、聯絡資訊、聯絡人照片、職稱和用戶聯絡人清單中的筆記</li><li>可能使中國追蹤聯邦僱員和承包商的位置、建立用於勒索的檔案、進行企業間諜活動</li><li>雖然 TikTok 的數據收集做法與其他社交媒體平台類似，但官員擔心外國行為者可能濫用</li></ul><p><strong>2. 內容操縱</strong></p><ul><li>戰略與國際研究中心（CSIS）的簡報強調，中國共產黨可能透過控制用戶動態、壓制異議或傳播虛假資訊來影響 TikTok 用戶</li></ul><h3 id="_6-3-最高法院裁決與行政命令" tabindex="-1">6.3 最高法院裁決與行政命令 <a class="header-anchor" href="#_6-3-最高法院裁決與行政命令" aria-label="Permalink to &quot;6.3 最高法院裁決與行政命令&quot;">​</a></h3><p><strong>最高法院裁決（2025 年 1 月 17 日）：</strong></p><ul><li>最高法院維持 PAFACA，確認它針對外國對手對通訊平台的控制，並基於令人信服的國家安全利益</li></ul><p><strong>川普政府的延期：</strong></p><ul><li><strong>2025 年 1 月 20 日</strong>：川普總統簽署行政命令，最初延期 75 天</li><li><strong>2025 年 4 月 4 日</strong>：再延期 75 天</li><li><strong>2025 年 6 月 17 日</strong>：計劃第三次延期 90 天</li><li><strong>當前狀態</strong>：禁令尚未執行</li></ul><h3 id="_6-4-爭議與辯論" tabindex="-1">6.4 爭議與辯論 <a class="header-anchor" href="#_6-4-爭議與辯論" aria-label="Permalink to &quot;6.4 爭議與辯論&quot;">​</a></h3><p><strong>支持禁令者：</strong></p><ul><li>中國法律要求公司協助情報收集</li><li>TikTok 可能成為影響美國公眾輿論的工具</li><li>保護國家安全優先於商業利益</li></ul><p><strong>反對禁令者：</strong></p><ul><li>侵犯 1.7 億美國用戶的言論自由</li><li>缺乏 TikTok 實際損害美國國家安全的具體證據</li><li>可能開啟政府封鎖社交媒體的先例</li><li>應透過數據保護立法而非禁令解決問題</li></ul><hr><h2 id="七、趨勢分析與未來展望" tabindex="-1">七、趨勢分析與未來展望 <a class="header-anchor" href="#七、趨勢分析與未來展望" aria-label="Permalink to &quot;七、趨勢分析與未來展望&quot;">​</a></h2><h3 id="_7-1-五大關鍵趨勢" tabindex="-1">7.1 五大關鍵趨勢 <a class="header-anchor" href="#_7-1-五大關鍵趨勢" aria-label="Permalink to &quot;7.1 五大關鍵趨勢&quot;">​</a></h3><p><strong>1. 數據在地化持續擴散</strong></p><ul><li>75% 國家已實施某種形式的數據落地規定</li><li>未來可能與更嚴格的網路安全要求結合</li><li>更明確的區域認證計畫</li><li>對跨國公司施加更大壓力，要求其隱私、安全和 AI 計畫符合國家主權目標</li></ul><p><strong>2. 執法強度與罰款金額上升</strong></p><ul><li>GDPR 罰款從數百萬歐元上升至數十億歐元</li><li>2025 年企業因不當數據在地化受罰，不僅因違規行為，也因不當數據傳輸或缺乏適當的在地化策略</li><li>DPAs 對 SCCs 和數據傳輸的審查更加嚴格</li></ul><p><strong>3. 跨境電商監管趨嚴</strong></p><ul><li>VAT/GST 改革：取消小額進口免稅額（越南、泰國）</li><li>商業註冊要求：外國平台必須在本地設立實體</li><li>平台責任擴大：從稅收代扣到內容審查</li><li>資訊透明度：賣家資訊、交易數據必須向政府報告</li></ul><p><strong>4. 數位服務稅擴散</strong></p><ul><li>法國 GAFA 稅從 3% 可能提高至 5%</li><li>更多國家在等待 OECD 兩支柱方案的同時實施單邊數位稅</li><li>與美國的貿易緊張關係可能升級</li></ul><p><strong>5. 網路分裂化（Splinternet）加速</strong></p><ul><li>美中歐三極格局固化</li><li>區域性數據流動協議（如中國與香港、澳門）</li><li>技術標準分歧（5G、AI、數據格式）</li><li>不同監管哲學導致的全球網路碎片化</li></ul><h3 id="_7-2-企業的挑戰與機遇" tabindex="-1">7.2 企業的挑戰與機遇 <a class="header-anchor" href="#_7-2-企業的挑戰與機遇" aria-label="Permalink to &quot;7.2 企業的挑戰與機遇&quot;">​</a></h3><p><strong>合規成本激增：</strong></p><ul><li>多司法管轄區數據儲存基礎設施</li><li>法務與合規團隊擴編</li><li>定期審計與評估（TIAs、DPIAs）</li><li>本地化商業模式調整</li></ul><p><strong>策略選擇：</strong></p><p><strong>1. 全面合規策略</strong></p><ul><li>在每個主要市場建立數據中心</li><li>雇用本地團隊處理合規事務</li><li>採用最高標準（如 GDPR）作為全球基準</li><li>適合：大型跨國科技公司</li></ul><p><strong>2. 選擇性進入策略</strong></p><ul><li>退出監管成本過高的市場</li><li>聚焦於監管友善的地區</li><li>透過本地合作夥伴間接進入</li><li>適合：中小型創新企業</li></ul><p><strong>3. 遊說與影響策略</strong></p><ul><li>參與政策制定過程</li><li>透過產業協會施壓</li><li>尋求母國政府支持</li><li>適合：具有政治影響力的大型企業</li></ul><h3 id="_7-3-政策制定者的挑戰" tabindex="-1">7.3 政策制定者的挑戰 <a class="header-anchor" href="#_7-3-政策制定者的挑戰" aria-label="Permalink to &quot;7.3 政策制定者的挑戰&quot;">​</a></h3><p><strong>平衡三難困境：</strong></p><ol><li><strong>安全</strong>：保護國家安全與公民隱私</li><li><strong>創新</strong>：維持數位經濟活力與競爭力</li><li><strong>開放</strong>：遵守國際貿易規則與承諾</li></ol><p><strong>風險：</strong></p><ul><li><strong>過度監管</strong>：扼殺創新、增加成本、減少消費者選擇</li><li><strong>監管不足</strong>：數據外洩、隱私侵犯、外國干預</li><li><strong>監管碎片化</strong>：企業無所適從、跨境貿易受阻</li></ul><p><strong>最佳實踐建議：</strong></p><ol><li><strong>清晰性</strong>：明確定義「重要數據」、「國家安全」等關鍵概念</li><li><strong>比例性</strong>：監管強度應與實際風險成比例</li><li><strong>一致性</strong>：對本地和外國企業一視同仁</li><li><strong>透明性</strong>：公開監管理由與決策過程</li><li><strong>靈活性</strong>：為合法商業活動提供豁免與替代方案</li><li><strong>國際協調</strong>：透過雙邊或多邊機制協調政策</li></ol><hr><h2 id="八、結論-重劃數位疆界的時代" tabindex="-1">八、結論：重劃數位疆界的時代 <a class="header-anchor" href="#八、結論-重劃數位疆界的時代" aria-label="Permalink to &quot;八、結論：重劃數位疆界的時代&quot;">​</a></h2><h3 id="_8-1-核心發現" tabindex="-1">8.1 核心發現 <a class="header-anchor" href="#_8-1-核心發現" aria-label="Permalink to &quot;8.1 核心發現&quot;">​</a></h3><p><strong>1. 數據落地已成全球趨勢</strong></p><ul><li>75% 國家實施某種形式的數據在地化</li><li>從先行者實驗（俄羅斯、中國）到全球擴散</li><li>執法力度顯著增強（罰款從百萬到數十億）</li></ul><p><strong>2. 監管動機多元且交織</strong></p><ul><li><strong>合法關切</strong>：國家安全、隱私保護、消費者權益</li><li><strong>經濟動機</strong>：保護本地產業、培育科技巨頭、增加稅收</li><li><strong>地緣政治</strong>：數位主權、科技競爭、影響力鬥爭</li></ul><p><strong>3. 影響深遠且複雜</strong></p><ul><li><strong>企業</strong>：合規成本上升、商業模式調整、市場准入障礙</li><li><strong>消費者</strong>：服務選擇減少、價格可能上漲、但隱私保護增強</li><li><strong>全球化</strong>：網路分裂化、貿易摩擦、標準分歧</li></ul><h3 id="_8-2-關鍵問題" tabindex="-1">8.2 關鍵問題 <a class="header-anchor" href="#_8-2-關鍵問題" aria-label="Permalink to &quot;8.2 關鍵問題&quot;">​</a></h3><p>這些監管措施究竟是：</p><ul><li><strong>必要的保護</strong>：在數位時代保護國家主權與公民權利？</li><li><strong>過度的干預</strong>：扼殺創新與全球化紅利的保護主義？</li></ul><p><strong>答案可能是：兩者兼有</strong>。</p><p>某些措施（如 GDPR 的隱私保護）代表合理監管，而其他措施（如印尼 TikTok Shop 禁令）則明顯具有保護主義色彩。關鍵在於透明度、比例性和一致性。</p><h3 id="_8-3-展望未來" tabindex="-1">8.3 展望未來 <a class="header-anchor" href="#_8-3-展望未來" aria-label="Permalink to &quot;8.3 展望未來&quot;">​</a></h3><p><strong>短期（2025-2027）：</strong></p><ul><li>更多國家實施數據在地化要求</li><li>跨境電商監管持續收緊（特別是東南亞）</li><li>GDPR 和 DMA 執法案例增加</li><li>美中科技脫鉤加速</li></ul><p><strong>中期（2028-2030）：</strong></p><ul><li>區域性數據流動協議形成（ASEAN、RCEP、CPTPP）</li><li>OECD 兩支柱稅改方案實施，可能取代單邊數位稅</li><li>AI 監管法規成熟（歐盟 AI Act 影響全球）</li><li>網路分裂化格局固化</li></ul><p><strong>長期（2030+）：</strong></p><ul><li>新一代全球數位治理框架？</li><li>區塊鏈與去中心化技術改變監管範式？</li><li>全球網路完全分裂為美中歐三大陣營？</li></ul><h3 id="_8-4-最終思考" tabindex="-1">8.4 最終思考 <a class="header-anchor" href="#_8-4-最終思考" aria-label="Permalink to &quot;8.4 最終思考&quot;">​</a></h3><p><strong>網路治理的本質是權力鬥爭</strong>：政府試圖重新掌控在全球化與數位化中流失的主權，企業試圖維持跨境運營的自由，公民試圖保護自身權利與自由。</p><p>在這場角力中，沒有完美的解決方案。但透明、比例、一致的監管原則，以及多方利害關係人的真誠對話，是找到平衡點的唯一途徑。</p><p><strong>數位疆界的重劃</strong> 正在進行，這不僅是技術與法律問題，更是關於我們想要什麼樣的數位未來的根本選擇。</p><hr><h2 id="參考資料" tabindex="-1">參考資料 <a class="header-anchor" href="#參考資料" aria-label="Permalink to &quot;參考資料&quot;">​</a></h2><h3 id="數據落地與全球趨勢" tabindex="-1">數據落地與全球趨勢 <a class="header-anchor" href="#數據落地與全球趨勢" aria-label="Permalink to &quot;數據落地與全球趨勢&quot;">​</a></h3><ol><li><a href="https://trustarc.com/resource/global-rise-data-localization-risks/" target="_blank" rel="noreferrer">The Global Impact of Data Localization Laws | TrustArc</a></li><li><a href="https://cookie-script.com/guides/data-localization-2025" target="_blank" rel="noreferrer">Data Localization in 2025 | CookieScript</a></li><li><a href="https://www.freshfields.com/en/our-thinking/campaigns/data-trends-2025/international-data-transfers-are-under-the-spotlight" target="_blank" rel="noreferrer">International data transfers are under the spotlight | Freshfields</a></li><li><a href="https://captaincompliance.com/education/data-localization-laws-by-country/" target="_blank" rel="noreferrer">Data Localization Laws By Country | Captain Compliance</a></li><li><a href="https://fpf.org/blog/what-to-expect-in-global-privacy-in-2025/" target="_blank" rel="noreferrer">What to Expect in Global Privacy in 2025 | Future of Privacy Forum</a></li></ol><h3 id="中國數據監管" tabindex="-1">中國數據監管 <a class="header-anchor" href="#中國數據監管" aria-label="Permalink to &quot;中國數據監管&quot;">​</a></h3><ol start="6"><li><a href="https://www.cac.gov.cn/2025-04/09/c_1745906286623776.htm" target="_blank" rel="noreferrer">数据出境安全管理政策问答（2025年4月）| 中央网络安全和信息化委员会办公室</a></li><li><a href="https://www.allbrightlaw.com/CN/10475/63efeb45f0af5dbe.aspx" target="_blank" rel="noreferrer">2024数据合规立法监管的回顾与2025年展望 | 锦天城律师事务所</a></li><li><a href="https://www.gov.cn/zhengce/content/202409/content_6977766.htm" target="_blank" rel="noreferrer">网络数据安全管理条例 | 中国政府网</a></li><li><a href="https://www.cac.gov.cn/2025-03/21/c_1744174598705025.htm" target="_blank" rel="noreferrer">《促进和规范数据跨境流动规定》实施一周年 | 中央网络安全和信息化委员会办公室</a></li></ol><h3 id="台灣監管政策" tabindex="-1">台灣監管政策 <a class="header-anchor" href="#台灣監管政策" aria-label="Permalink to &quot;台灣監管政策&quot;">​</a></h3><ol start="10"><li><a href="https://kpmg.com/tw/zh/home/insights/2024/08/online-shopping-security-and-personal-data-management.html" target="_blank" rel="noreferrer">詐騙猖獗，電商應加強網購安全及個資管理 | KPMG</a></li><li><a href="https://plainlaw.me/posts/legal-miracle-drug" target="_blank" rel="noreferrer">「打詐四法草案」是法律特效藥？| 法律白話文運動</a></li><li><a href="https://www.tph.moj.gov.tw/4421/4475/632364/1205402/post" target="_blank" rel="noreferrer">打詐四法是甚麼？| 臺灣高等檢察署</a></li></ol><h3 id="印尼-tiktok-shop-案例" tabindex="-1">印尼 TikTok Shop 案例 <a class="header-anchor" href="#印尼-tiktok-shop-案例" aria-label="Permalink to &quot;印尼 TikTok Shop 案例&quot;">​</a></h3><ol start="13"><li><a href="https://www.cnbc.com/2023/10/04/tiktok-halts-e-commerce-service-in-indonesia-following-ban.html" target="_blank" rel="noreferrer">TikTok halts e-commerce service in Indonesia following ban | CNBC</a></li><li><a href="https://www.asiapacific.ca/publication/indonesias-new-e-commerce-regulations-take-bite-out-tiktoks" target="_blank" rel="noreferrer">Indonesia&#39;s New E-commerce Regulations Take a Bite Out of TikTok&#39;s Market Share | Asia Pacific Foundation</a></li><li><a href="https://www.aseanbriefing.com/news/indonesias-social-media-e-commerce-ban/" target="_blank" rel="noreferrer">Indonesia&#39;s Social Media E-Commerce Ban | ASEAN Briefing</a></li></ol><h3 id="越南跨境電商案例" tabindex="-1">越南跨境電商案例 <a class="header-anchor" href="#越南跨境電商案例" aria-label="Permalink to &quot;越南跨境電商案例&quot;">​</a></h3><ol start="16"><li><a href="https://kr-asia.com/regulatory-hurdles-stall-temu-in-vietnam-amid-southeast-asia-e-commerce-boom" target="_blank" rel="noreferrer">Regulatory hurdles stall Temu in Vietnam | KrAsia</a></li><li><a href="https://www.caixinglobal.com/2024-12-17/temu-suffers-first-big-setback-as-vietnam-suspends-its-operations-102268732.html" target="_blank" rel="noreferrer">Temu Suffers First Big Setback as Vietnam Suspends Its Operations | Caixin Global</a></li><li><a href="https://dig.watch/updates/vietnam-suspends-operations-of-temu-intensifying-scrutiny-of-foreign-e-commerce-platforms" target="_blank" rel="noreferrer">Vietnam suspends operations of Temu | Digital Watch Observatory</a></li></ol><h3 id="gdpr-與歐盟監管" tabindex="-1">GDPR 與歐盟監管 <a class="header-anchor" href="#gdpr-與歐盟監管" aria-label="Permalink to &quot;GDPR 與歐盟監管&quot;">​</a></h3><ol start="19"><li><a href="https://secureprivacy.ai/blog/cross-border-data-transfers-2025-guide" target="_blank" rel="noreferrer">Cross Border Data Transfers: 2025 Guide | SecurePrivacy</a></li><li><a href="https://www.cookieyes.com/blog/gdpr-fines/" target="_blank" rel="noreferrer">Guide to GDPR Fines and Penalties | CookieYes</a></li><li><a href="https://www.compliancehub.wiki/gdpr-2025-updates-navigating-cross-border-transfers-and-stricter-breach-reporting/" target="_blank" rel="noreferrer">GDPR 2025 Updates | ComplianceHub</a></li></ol><h3 id="印度-dpdpa" tabindex="-1">印度 DPDPA <a class="header-anchor" href="#印度-dpdpa" aria-label="Permalink to &quot;印度 DPDPA&quot;">​</a></h3><ol start="22"><li><a href="https://www.americanbar.org/groups/business_law/resources/business-law-today/2025-may/india-data-protection-law/" target="_blank" rel="noreferrer">India&#39;s New Personal Data Protection Law | American Bar Association</a></li><li><a href="https://trilegal.com/dataprotection/the-draft-digital-personal-data-protection-rules-2025-operationalising-indias-data-protection-law/" target="_blank" rel="noreferrer">The Draft Digital Personal Data Protection Rules, 2025 | Trilegal</a></li><li><a href="https://www.biometricupdate.com/202511/india-notifies-its-sweeping-digital-personal-data-protection-rules" target="_blank" rel="noreferrer">India notifies Digital Personal Data Protection rules | Biometric Update</a></li></ol><h3 id="俄羅斯數據在地化" tabindex="-1">俄羅斯數據在地化 <a class="header-anchor" href="#俄羅斯數據在地化" aria-label="Permalink to &quot;俄羅斯數據在地化&quot;">​</a></h3><ol start="25"><li><a href="https://www.brookings.edu/articles/russia-is-weaponizing-its-data-laws-against-foreign-organizations/" target="_blank" rel="noreferrer">Russia is weaponizing its data laws | Brookings</a></li><li><a href="https://konsugroup.com/en/news/new-requirements-personal-data-protection-russia-2025-07/" target="_blank" rel="noreferrer">New requirements for localization of personal data in Russia | Konsu</a></li><li><a href="https://captaincompliance.com/education/russia-data-localization-law/" target="_blank" rel="noreferrer">Russia Data Localization Law: 2025 Guide | Captain Compliance</a></li></ol><h3 id="歐盟數位市場法-dma" tabindex="-1">歐盟數位市場法 (DMA) <a class="header-anchor" href="#歐盟數位市場法-dma" aria-label="Permalink to &quot;歐盟數位市場法 (DMA)&quot;">​</a></h3><ol start="28"><li><a href="https://digital-markets-act.ec.europa.eu/index_en" target="_blank" rel="noreferrer">Digital Markets Act | European Commission</a></li><li><a href="https://digital-markets-act.ec.europa.eu/gatekeepers_en" target="_blank" rel="noreferrer">DMA designated Gatekeepers | European Commission</a></li><li><a href="https://secureprivacy.ai/blog/digital-markets-act-dma-explained-2025" target="_blank" rel="noreferrer">Digital Markets Act (DMA) Explained [2025] | SecurePrivacy</a></li></ol><h3 id="美國-tiktok-禁令" tabindex="-1">美國 TikTok 禁令 <a class="header-anchor" href="#美國-tiktok-禁令" aria-label="Permalink to &quot;美國 TikTok 禁令&quot;">​</a></h3><ol start="31"><li><a href="https://en.wikipedia.org/wiki/Restrictions_on_TikTok_in_the_United_States" target="_blank" rel="noreferrer">Restrictions on TikTok in the United States | Wikipedia</a></li><li><a href="https://www.rand.org/pubs/commentary/2024/08/tiktok-is-a-threat-to-national-security-but-not-for.html" target="_blank" rel="noreferrer">TikTok Is a Threat to National Security | RAND</a></li><li><a href="https://jsis.washington.edu/news/u-s-tiktok-ban-national-security-and-civil-liberties-concerns/" target="_blank" rel="noreferrer">U.S. TikTok Ban: National Security and Civil Liberties | University of Washington</a></li></ol><h3 id="巴西-lgpd" tabindex="-1">巴西 LGPD <a class="header-anchor" href="#巴西-lgpd" aria-label="Permalink to &quot;巴西 LGPD&quot;">​</a></h3><ol start="34"><li><a href="https://www.trade.gov/market-intelligence/brazils-new-rules-international-data-transfers" target="_blank" rel="noreferrer">Brazil&#39;s New Rules on International Data Transfers | U.S. Trade</a></li><li><a href="https://www.insideprivacy.com/data-transfers/brazil-issues-new-regulation-on-international-data-transfers/" target="_blank" rel="noreferrer">Brazil Issues New Regulation on International Data Transfers | Inside Privacy</a></li></ol><h3 id="澳洲隱私法改革" tabindex="-1">澳洲隱私法改革 <a class="header-anchor" href="#澳洲隱私法改革" aria-label="Permalink to &quot;澳洲隱私法改革&quot;">​</a></h3><ol start="36"><li><a href="https://www.oaic.gov.au/news/media-centre/pasing-of-bill-a-significant-step-for-australias-privacy-law" target="_blank" rel="noreferrer">Privacy and Other Legislation Amendment Act 2024 | OAIC</a></li><li><a href="https://secureprivacy.ai/blog/what-australia-privacy-act-reforms-mean-for-your-business-2025" target="_blank" rel="noreferrer">What Australia Privacy Act Reforms Mean 2025 | SecurePrivacy</a></li><li><a href="https://www.privacyworld.blog/2024/12/first-tranche-of-reforms-to-australian-privacy-law-passed-with-amendments/" target="_blank" rel="noreferrer">First Tranche of Reforms to Australian Privacy Law | Privacy World</a></li></ol><h3 id="南韓-pipa" tabindex="-1">南韓 PIPA <a class="header-anchor" href="#南韓-pipa" aria-label="Permalink to &quot;南韓 PIPA&quot;">​</a></h3><ol start="39"><li><a href="https://www.truendo.com/en-US/blog/data-privacy-law-updates-in-asia-pacific" target="_blank" rel="noreferrer">Data Privacy Law Updates in Asia-Pacific 2024 | Truendo</a></li><li><a href="https://www.loc.gov/item/global-legal-monitor/2025-06-23/south-korea-amended-personal-information-protection-act-expands-individuals-control-over-personal-data" target="_blank" rel="noreferrer">South Korea Amended PIPA | Library of Congress</a></li></ol><h3 id="泰國稅收監管" tabindex="-1">泰國稅收監管 <a class="header-anchor" href="#泰國稅收監管" aria-label="Permalink to &quot;泰國稅收監管&quot;">​</a></h3><ol start="41"><li><a href="https://www.vatupdate.com/2024/09/05/new-tax-regulations-for-e-commerce-businesses-and-foreign-online-platforms-in-thailand/" target="_blank" rel="noreferrer">New Tax Regulations for E-commerce in Thailand | VATupdate</a></li><li><a href="https://goriouxsiam.com/2024/06/17/navigating-thailands-e-commerce-tax-regulations/" target="_blank" rel="noreferrer">Navigating Thailand&#39;s E-commerce Tax Regulations | Gorioux Siam</a></li></ol><h3 id="法國數位服務稅" tabindex="-1">法國數位服務稅 <a class="header-anchor" href="#法國數位服務稅" aria-label="Permalink to &quot;法國數位服務稅&quot;">​</a></h3><ol start="43"><li><a href="https://1stopvat.com/france-increase-of-digital-services-tax-2025/" target="_blank" rel="noreferrer">France - Increase of Digital Services Tax 2025 | 1stopVAT</a></li><li><a href="https://www.vatupdate.com/2024/11/27/france-plans-to-increase-digital-services-tax-rate-to-5-in-2025/" target="_blank" rel="noreferrer">France Plans to Increase DST to 5% | VATupdate</a></li><li><a href="https://itif.org/publications/2025/02/11/france-digital-tax-policy/" target="_blank" rel="noreferrer">France&#39;s Digital Tax Policy | ITIF</a></li></ol><h3 id="數位主權與保護主義" tabindex="-1">數位主權與保護主義 <a class="header-anchor" href="#數位主權與保護主義" aria-label="Permalink to &quot;數位主權與保護主義&quot;">​</a></h3><ol start="46"><li><a href="https://itif.org/publications/2025/03/07/the-global-spread-of-protectionist-policies-that-squeeze-american-tech-companies/" target="_blank" rel="noreferrer">The Global Spread of Protectionist Policies | ITIF</a></li><li><a href="https://www.wita.org/wp-content/uploads/2021/09/Digital-sovereignty-protectionism-or-autonomy-Hinrich-Foundation-Deborah-Elms-September-2021.pdf" target="_blank" rel="noreferrer">Digital Sovereignty: protectionism or autonomy? | Hinrich Foundation</a></li><li><a href="https://www.weforum.org/stories/2025/01/europe-digital-sovereignty/" target="_blank" rel="noreferrer">What is digital sovereignty? | World Economic Forum</a></li></ol><hr>',272)])])}const d=a(e,[["render",o]]);export{c as __pageData,d as default};
